{
  "summary": "The paper proposes embedding-based Mahalanobis distance (RMD) and logistic regression classifiers for out-of-distribution (OOD) detection in conditional language models, combined with perplexity to enable selective generation that abstains on low-quality inputs. Evaluated on summarization and translation tasks, the methods outperform perplexity and other baselines in OOD detection and improve correlation with output quality, facilitating safer deployment of language models.",
  "strengths": [
    {
      "point": "Proposes lightweight and effective embedding-based OOD detection methods tailored for encoder-decoder language models",
      "evidence": "RMD and logistic regression classifiers use input/output embeddings and Gaussian fitting to distinguish in-domain from OOD inputs, outperforming perplexity and external metrics like COMET and Prism."
    },
    {
      "point": "Demonstrates that combining embedding-based OOD scores with perplexity improves output quality prediction and selective generation",
      "evidence": "Combined scores increase correlation with human quality ratings and BLEURT by up to 12% absolute and enable effective abstention strategies that improve average output quality."
    },
    {
      "point": "Provides a comprehensive evaluation framework including human quality ratings and multiple OOD scenarios",
      "evidence": "Experiments cover near-domain and far-domain splits for summarization and translation, with human annotations and multiple metrics (AUROC, correlation) to assess detection and selective generation."
    }
  ],
  "weaknesses": [
    {
      "point": "Lacks empirical comparison to recent strong OOD detection baselines specific to language models",
      "evidence": "No experiments or discussion on energy-based methods (Liu et al., 2020), contrastive learning approaches (Hendrycks et al., 2021), or standard baselines like MSP and ODIN adapted for language models."
    },
    {
      "point": "Insufficient validation of key methodological assumptions and design choices",
      "evidence": "No quantitative evidence or visualization validating Gaussian assumption on embeddings; no ablations on embedding pooling strategies such as CLS token or attention-weighted pooling."
    },
    {
      "point": "Evaluation metrics and analyses are incomplete and lack calibration and robustness assessments",
      "evidence": "Only AUROC reported without precision-recall or average precision; no calibration analysis of OOD scores; no sensitivity analyses on background dataset choice or abstention threshold selection; no error analysis or qualitative failure case studies."
    },
    {
      "point": "Reproducibility details are insufficient",
      "evidence": "Missing specifics on background dataset size, preprocessing, logistic regression training details, and thresholding procedures for RMD."
    },
    {
      "point": "Limited generalizability and scalability discussion",
      "evidence": "Experiments restricted to encoder-decoder models and two tasks; no analysis of computational overhead; no discussion on extending to decoder-only models or impact of model size variations."
    },
    {
      "point": "No consideration of embedding drift over model updates or potential biases in foreground/background data",
      "evidence": "Embedding distributions may shift with fine-tuning, affecting OOD detection reliability; biases in datasets could skew detection but are not addressed."
    }
  ],
  "questions": [
    {
      "question": "How do the proposed methods compare quantitatively to recent state-of-the-art OOD detection techniques specifically designed for language models?",
      "motivation": "Understanding relative performance is critical to position the novelty and practical value of the methods."
    },
    {
      "question": "How robust are the Gaussian embedding assumptions and the chosen embedding pooling strategies across different models and tasks?",
      "motivation": "Validating these assumptions affects the method’s reliability and generalizability."
    },
    {
      "question": "How sensitive is OOD detection performance to the choice and size of the background dataset, and how should abstention thresholds be calibrated in practice?",
      "motivation": "These factors impact deployment feasibility and effectiveness of selective generation."
    },
    {
      "question": "Are the OOD scores well-calibrated and reliable for thresholding decisions in selective generation, especially under adversarial or subtle distributional shifts?",
      "motivation": "Calibration affects trustworthiness and safety in real-world applications."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
